def gen(rng, size):
    n = max(1, size)
    arr = [rng.randint(0, 10000)]
    for _ in range(n - 1):
        arr.append(rng.randint(0, 10000) if rng.random() < 0.85 else None)
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

