class Solution:
    def rob(self, root):
        # memoized: best for subtree given whether parent was robbed
        from functools import lru_cache
        memo = {}
        def best(node, parent_robbed):
            if not node:
                return 0
            key = (id(node), parent_robbed)
            if key in memo:
                return memo[key]
            # option: skip this node
            skip = best(node.left, False) + best(node.right, False)
            if parent_robbed:
                memo[key] = skip
                return skip
            # option: rob this node
            take = node.val + best(node.left, True) + best(node.right, True)
            res = max(skip, take)
            memo[key] = res
            return res
        return best(root, False)

