class Solution:
    def rob(self, root):
        def dfs(node):
            if not node:
                return (0, 0)
            l = dfs(node.left)
            r = dfs(node.right)
            rob_node = node.val + l[1] + r[1]
            skip_node = max(l) + max(r)
            return (rob_node, skip_node)
        return max(dfs(root))

