    function dfs(node) {
        if (!node) return [0, 0];
        const l = dfs(node.left);
        const r = dfs(node.right);
        const robNode = node.val + l[1] + r[1];
        const skipNode = Math.max(l[0], l[1]) + Math.max(r[0], r[1]);
        return [robNode, skipNode];
    }
    const res = dfs(root);
    return Math.max(res[0], res[1]);
